def login(username, password, correlation_id):
    user = repo.find(username)
    if not user or not verify(user, password):
        logger.info('audit', audit=True, control='log.audit', action='auth.login', actor=username, target={'type':'session','id':None}, outcome='failure', reason='invalid_credentials', ts=now, correlation_id=correlation_id)
        return Response(status=401)
    logger.info('audit', audit=True, control='log.audit', action='auth.login', actor=user.id, target={'type':'session','id':user.id}, outcome='success', ts=now, correlation_id=correlation_id)
    return Response(status=200)

